import redis
from functools import lru_cache

# Configure Redis connection
REDIS_HOST = 'your_redis_host'
REDIS_PORT = 6379
REDIS_DB = 0
REDIS_PASSWORD = 'your_redis_password'

# Create Redis client
redis_client = redis.StrictRedis(host=REDIS_HOST, port=REDIS_PORT, db=REDIS_DB, password=REDIS_PASSWORD)

# Store session tokens with TTL (e.g., 1 hour)
def store_session_token(user_id, token):
    return redis_client.setex(f'session:{user_id}', 3600, token)

# Retrieve session token
@lru_cache(maxsize=None)
def get_session_token(user_id):
    return redis_client.get(f'session:{user_id}')

# Store API keys with TTL (e.g., 24 hours)
def store_api_key(api_key_id, api_key):
    return redis_client.setex(f'api_key:{api_key_id}', 86400, api_key)

# Retrieve API key
@lru_cache(maxsize=None)
def get_api_key(api_key_id):
    return redis_client.get(f'api_key:{api_key_id}')

# Example usage
if __name__ == "__main__":
    store_session_token('user123', 'abc123')
    print(get_session_token('user123'))
    
    store_api_key('key456', 'def456')
